const img = document.querySelector('img');

function agrandir() { this.style.transform = 'scale(1.2)'; }
function reduire() { this.style.transform = 'scale(1)'; }
function logClick() { console.log('Image cliquée'); }

img.addEventListener('mouseover', agrandir);
img.addEventListener('mouseout', reduire);
img.addEventListener('click', logClick);

// Pour désactiver le zoom plus tard :
function desactiverZoom() {
  img.removeEventListener('mouseover', agrandir);
  img.removeEventListener('mouseout', reduire);
}
